import React, {useState} from 'react';
import {ScrollView, Text, TextInput, TouchableOpacity, StyleSheet} from 'react-native';

export default function SignupScreen({navigation}){
  const [email,setEmail]=useState('');
  const [pw,setPw]=useState('');
  const [pw2,setPw2]=useState('');
  return (
    <ScrollView contentContainerStyle={styles.form}>
      <Text style={styles.title}>Create Your Account</Text>
      <TextInput placeholder="Email or Phone Number" style={styles.input} value={email} onChangeText={setEmail} />
      <TextInput placeholder="Password" secureTextEntry style={styles.input} value={pw} onChangeText={setPw} />
      <TextInput placeholder="Confirm Password" secureTextEntry style={styles.input} value={pw2} onChangeText={setPw2} />
      <TouchableOpacity style={styles.primaryButton} onPress={()=>navigation.navigate('BankConnect')}><Text style={styles.btnText}>Create Account</Text></TouchableOpacity>
      <TouchableOpacity onPress={()=>navigation.replace('Main')}><Text style={styles.smallText}>Already have an account? Log in</Text></TouchableOpacity>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  form:{padding:20},
  title:{fontSize:20,fontWeight:'700',marginBottom:12},
  input:{borderWidth:1,borderColor:'#ddd',padding:10,borderRadius:8,marginBottom:10},
  primaryButton:{backgroundColor:'#0a84ff',padding:12,paddingHorizontal:24,borderRadius:8,marginTop:16,alignItems:'center'},
  btnText:{color:'#fff',fontWeight:'700'},
  smallText:{color:'#666',marginTop:8,textAlign:'center'}
});
